leetcode-167-two-sum-ii.answer:
def two_sum(numbers, target):
    left, right = 0, len(numbers) - 1
    while left < right:
        s = numbers[left] + numbers[right]
        if s == target:
            return [left + 1, right + 1]
        elif s < target:
            left += 1
        else:
            right -= 1
    return []

geeksforgeeks-pair-with-given-sum-in-a-s.answer:
def count_pairs_with_sum(arr, target):
    left, right = 0, len(arr) - 1
    count = 0
    while left < right:
        s = arr[left] + arr[right]
        if s == target:
            if arr[left] == arr[right]:
                n = right - left + 1
                count += n * (n - 1) // 2
                break
            else:
                left_count = 1
                while left + 1 < right and arr[left + 1] == arr[left]:
                    left += 1
                    left_count += 1
                right_count = 1
                while right - 1 > left and arr[right - 1] == arr[right]:
                    right -= 1
                    right_count += 1
                count += left_count * right_count
                left += 1
                right -= 1
        elif s < target:
            left += 1
        else:
            right -= 1
    return count

hackerrank-ice-cream-parlor.answer:
def ice_cream_parlor(money, prices):
    indexed = sorted(range(len(prices)), key=lambda i: prices[i])
    left, right = 0, len(indexed) - 1
    while left < right:
        total = prices[indexed[left]] + prices[indexed[right]]
        if total == money:
            a, b = indexed[left] + 1, indexed[right] + 1
            return sorted([a, b])
        elif total < money:
            left += 1
        else:
            right -= 1
    return []

