from collections import deque

def first_negative_in_every_window(arr, k):
    result = []
    neg_indices = deque()
    for i in range(len(arr)):
        if arr[i] < 0:
            neg_indices.append(i)
        if i >= k - 1:
            while neg_indices and neg_indices[0] <= i - k:
                neg_indices.popleft()
            result.append(arr[neg_indices[0]] if neg_indices else 0)
    return result

leetcode-239-sliding-window-maximum.answer:
from collections import deque

def max_sliding_window(nums, k):
    dq = deque()
    result = []
    for i, num in enumerate(nums):
        while dq and nums[dq[-1]] < num:
            dq.pop()
        dq.append(i)
        if dq[0] <= i - k:
            dq.popleft()
        if i >= k - 1:
            result.append(nums[dq[0]])
    return result

leetcode-438-find-all-anagrams-in-a-stri.answer:
from collections import Counter

def find_anagrams(s, p):
    result = []
    k = len(p)
    if k > len(s):
        return result
    p_count = Counter(p)
    window_count = Counter(s[:k])
    if window_count == p_count:
        result.append(0)
    for i in range(k, len(s)):
        left_char = s[i - k]
        window_count[left_char] -= 1
        if window_count[left_char] == 0:
            del window_count[left_char]
        window_count[s[i]] += 1
        if window_count == p_count:
            result.append(i - k + 1)
    return result

