def longest_k_unique_substring(s, k):
    counts = {}
    left = 0
    best = -1
    for right, ch in enumerate(s):
        counts[ch] = counts.get(ch, 0) + 1
        while len(counts) > k:
            left_ch = s[left]
            counts[left_ch] -= 1
            if counts[left_ch] == 0:
                del counts[left_ch]
            left += 1
        if len(counts) == k:
            best = max(best, right - left + 1)
    return best

