leetcode-304-range-sum-query-2d-immutabl.answer:
class NumMatrix:
    def __init__(self, matrix):
        rows, cols = len(matrix), len(matrix[0])
        self.prefix = [[0] * (cols + 1) for _ in range(rows + 1)]
        for i in range(rows):
            for j in range(cols):
                self.prefix[i + 1][j + 1] = (
                    matrix[i][j]
                    + self.prefix[i][j + 1]
                    + self.prefix[i + 1][j]
                    - self.prefix[i][j]
                )

    def sumRegion(self, row1, col1, row2, col2):
        return (
            self.prefix[row2 + 1][col2 + 1]
            - self.prefix[row1][col2 + 1]
            - self.prefix[row2 + 1][col1]
            + self.prefix[row1][col1]
        )

leetcode-1314-matrix-block-sum.answer:
def matrix_block_sum(mat, k):
    rows, cols = len(mat), len(mat[0])
    prefix = [[0] * (cols + 1) for _ in range(rows + 1)]
    for i in range(rows):
        for j in range(cols):
            prefix[i + 1][j + 1] = (
                mat[i][j] + prefix[i][j + 1] + prefix[i + 1][j] - prefix[i][j]
            )

    answer = [[0] * cols for _ in range(rows)]
    for i in range(rows):
        for j in range(cols):
            r1, c1 = max(0, i - k), max(0, j - k)
            r2, c2 = min(rows - 1, i + k), min(cols - 1, j + k)
            answer[i][j] = (
                prefix[r2 + 1][c2 + 1]
                - prefix[r1][c2 + 1]
                - prefix[r2 + 1][c1]
                + prefix[r1][c1]
            )
    return answer

leetcode-363-max-sum-of-rectangle-no-lar.answer:
import bisect

def max_sum_submatrix(matrix, k):
    rows, cols = len(matrix), len(matrix[0])
    best = float('-inf')
    for top in range(rows):
        col_sums = [0] * cols
        for bottom in range(top, rows):
            for c in range(cols):
                col_sums[c] += matrix[bottom][c]

            prefix_sorted = [0]
            running = 0
            for c in range(cols):
                running += col_sums[c]
                idx = bisect.bisect_left(prefix_sorted, running - k)
                if idx < len(prefix_sorted):
                    best = max(best, running - prefix_sorted[idx])
                bisect.insort(prefix_sorted, running)
    return best

