leetcode-34-find-first-and-last-position.answer:
def search_range(nums, target):
    def find_bound(is_first):
        low, high = 0, len(nums) - 1
        result = -1
        while low <= high:
            mid = (low + high) // 2
            if nums[mid] == target:
                result = mid
                if is_first:
                    high = mid - 1
                else:
                    low = mid + 1
            elif nums[mid] < target:
                low = mid + 1
            else:
                high = mid - 1
        return result

    return [find_bound(True), find_bound(False)]

