def aggressive_cows(positions, cows):
    positions.sort()

    def feasible(min_dist):
        placed = 1
        last_position = positions[0]
        for pos in positions[1:]:
            if pos - last_position >= min_dist:
                placed += 1
                last_position = pos
        return placed >= cows

    low, high = 1, positions[-1] - positions[0]
    best = 0
    while low <= high:
        mid = (low + high) // 2
        if feasible(mid):
            best = mid
            low = mid + 1
        else:
            high = mid - 1
    return best

