from functools import lru_cache

def get_length_of_optimal_compression(s, k):
    n = len(s)

    def calc_len(cnt):
        if cnt == 0:
            return 0
        if cnt == 1:
            return 1
        if cnt < 10:
            return 2
        if cnt < 100:
            return 3
        return 4

    @lru_cache(maxsize=None)
    def dp(i, k):
        if k < 0:
            return float('inf')
        if n - i <= k:
            return 0
        best = dp(i + 1, k - 1)
        cnt = 0
        deleted = 0
        for j in range(i, n):
            if s[j] == s[i]:
                cnt += 1
            else:
                deleted += 1
                if deleted > k:
                    break
            best = min(best, calc_len(cnt) + dp(j + 1, k - deleted))
        return best

    return dp(0, k)

