def longest_dup_substring(s):
    n = len(s)
    nums = [ord(c) - ord('a') for c in s]
    base = 26
    mod = (1 << 61) - 1

    def search(length):
        h = 0
        for i in range(length):
            h = (h * base + nums[i]) % mod
        seen = {h: [0]}
        high_order = pow(base, length - 1, mod)
        for start in range(1, n - length + 1):
            h = (h - nums[start - 1] * high_order) % mod
            h = (h * base + nums[start + length - 1]) % mod
            h %= mod
            if h in seen:
                for prev_start in seen[h]:
                    if s[prev_start:prev_start + length] == s[start:start + length]:
                        return start
                seen[h].append(start)
            else:
                seen[h] = [start]
        return -1

    lo, hi = 1, n - 1
    result_start, result_len = -1, 0
    while lo <= hi:
        mid = (lo + hi) // 2
        pos = search(mid)
        if pos != -1:
            result_start, result_len = pos, mid
            lo = mid + 1
        else:
            hi = mid - 1
    return s[result_start:result_start + result_len] if result_start != -1 else ""

