    stack = []
    to_remove = k
    for digit in num:
        while stack and to_remove > 0 and stack[-1] > digit:
            stack.pop()
            to_remove -= 1
        stack.append(digit)
    if to_remove > 0:
        stack = stack[:-to_remove]
    result = ''.join(stack).lstrip('0')
    return result if result else '0'

