class MinStackConstantSpace:
    def __init__(self):
        self.stack = []
        self.min_val = float('inf')

    def push(self, val: int) -> None:
        if not self.stack:
            self.stack.append(val)
            self.min_val = val
        elif val >= self.min_val:
            self.stack.append(val)
        else:
            self.stack.append(2 * val - self.min_val)  # encoded value
            self.min_val = val

    def pop(self) -> int:
        top = self.stack.pop()
        if top < self.min_val:
            actual = self.min_val
            self.min_val = 2 * self.min_val - top  # restore previous min
            return actual
        return top

    def get_min(self) -> int:
        return self.min_val

