class MaxStack:
    def __init__(self):
        self.main = []
        self.track = []

    def push(self, x: int) -> None:
        self.main.append(x)
        m = x if not self.track else max(x, self.track[-1])
        self.track.append(m)

    def pop(self) -> int:
        self.track.pop()
        return self.main.pop()

    def top(self) -> int:
        return self.main[-1]

    def peekMax(self) -> int:
        return self.track[-1]

    def popMax(self) -> int:
        max_val = self.track[-1]
        buffer = []
        while self.main[-1] != max_val:
            buffer.append(self.pop())
        self.pop()
        while buffer:
            self.push(buffer.pop())
        return max_val

