        self.data = data
        self.left = None
        self.right = None

def levelOrder(root):
    if root is None:
        return []
    output = []
    queue = deque([root])
    while queue:
        node = queue.popleft()
        output.append(node.data)
        if node.left:
            queue.append(node.left)
        if node.right:
            queue.append(node.right)
    return output

