from collections import deque

def checkSorted(n, q):
    stack = []
    expected = 1
    q = deque(q)
    while q:
        front = q[0]
        if front == expected:
            q.popleft()
            expected += 1
        elif stack and stack[-1] == expected:
            stack.pop()
            expected += 1
        else:
            stack.append(q.popleft())
    while stack and stack[-1] == expected:
        stack.pop()
        expected += 1
    return len(stack) == 0

