from collections import deque, defaultdict

def shortest_reach(n, edges, s):
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    dist = {node: -1 for node in range(1, n + 1)}
    dist[s] = 0
    queue = deque([s])

    while queue:
        node = queue.popleft()
        for neighbor in graph[node]:
            if dist[neighbor] == -1:
                dist[neighbor] = dist[node] + 1
                queue.append(neighbor)

    return [dist[node] for node in range(1, n + 1) if node != s]

