import heapq

def max_probability(n, edges, succ_prob, start, end):
    graph = [[] for _ in range(n)]
    for (u, v), p in zip(edges, succ_prob):
        graph[u].append((v, p))
        graph[v].append((u, p))

    prob = [0.0] * n
    prob[start] = 1.0
    heap = [(-1.0, start)]

    while heap:
        neg_p, node = heapq.heappop(heap)
        p = -neg_p
        if p < prob[node]:
            continue
        if node == end:
            return p
        for neighbor, edge_p in graph[node]:
            new_p = p * edge_p
            if new_p > prob[neighbor]:
                prob[neighbor] = new_p
                heapq.heappush(heap, (-new_p, neighbor))

    return 0.0

leetcode-1631-path-with-minimum-effort.answer:
import heapq

def minimum_effort_path(heights):
    rows, cols = len(heights), len(heights[0])
    effort = [[float('inf')] * cols for _ in range(rows)]
    effort[0][0] = 0
    heap = [(0, 0, 0)]
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    while heap:
        cur_effort, r, c = heapq.heappop(heap)
        if cur_effort > effort[r][c]:
            continue
        if r == rows - 1 and c == cols - 1:
            return cur_effort
        for dr, dc in directions:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols:
                new_effort = max(cur_effort, abs(heights[nr][nc] - heights[r][c]))
                if new_effort < effort[nr][nc]:
                    effort[nr][nc] = new_effort
                    heapq.heappush(heap, (new_effort, nr, nc))

    return 0

leetcode-787-cheapest-flights-within-k-s.answer:
def find_cheapest_price(n, flights, src, dst, k):
    dist = [float('inf')] * n
    dist[src] = 0

    for _ in range(k + 1):
        new_dist = dist[:]
        for u, v, w in flights:
            if dist[u] != float('inf') and dist[u] + w < new_dist[v]:
                new_dist[v] = dist[u] + w
        dist = new_dist

    return dist[dst] if dist[dst] != float('inf') else -1

geeksforgeeks-bellman-ford-algorithm.answer:
def bellman_ford(v, edges, src):
    dist = [float('inf')] * v
    dist[src] = 0

    for _ in range(v - 1):
        for u, w, weight in edges:
            if dist[u] != float('inf') and dist[u] + weight < dist[w]:
                dist[w] = dist[u] + weight

    for u, w, weight in edges:
        if dist[u] != float('inf') and dist[u] + weight < dist[w]:
            return None

    return dist

