def has_negative_cycle(v, edges):
    dist = [0] * v

    for _ in range(v - 1):
        for u, w, weight in edges:
            if dist[u] + weight < dist[w]:
                dist[w] = dist[u] + weight

    for u, w, weight in edges:
        if dist[u] + weight < dist[w]:
            return True

    return False

leetcode-1334-find-the-city-with-the-sma.answer:
def find_the_city(n, edges, distance_threshold):
    INF = float('inf')
    dist = [[INF] * n for _ in range(n)]
    for i in range(n):
        dist[i][i] = 0
    for u, v, w in edges:
        dist[u][v] = min(dist[u][v], w)
        dist[v][u] = min(dist[v][u], w)

    for k in range(n):
        for i in range(n):
            if dist[i][k] == INF:
                continue
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]

    best_city = -1
    best_count = n + 1
    for i in range(n):
        count = sum(1 for j in range(n) if i != j and dist[i][j] <= distance_threshold)
        if count <= best_count:
            best_count = count
            best_city = i

    return best_city

geeksforgeeks-floyd-warshall-algorithm.answer:
def floyd_warshall(matrix):
    n = len(matrix)
    INF = float('inf')
    dist = [[matrix[i][j] if matrix[i][j] != 0 or i == j else INF for j in range(n)] for i in range(n)]

    for k in range(n):
        for i in range(n):
            if dist[i][k] == INF:
                continue
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]

    return dist

