def city_of_blinding_lights(n, edges, queries):
    INF = float('inf')
    dist = [[INF] * (n + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        dist[i][i] = 0
    for u, v, w in edges:
        dist[u][v] = min(dist[u][v], w)

    for k in range(1, n + 1):
        for i in range(1, n + 1):
            if dist[i][k] == INF:
                continue
            for j in range(1, n + 1):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]

    results = []
    for a, b in queries:
        results.append(dist[a][b] if dist[a][b] != INF else -1)
    return results

geeksforgeeks-kruskals-minimum-spanning-.answer:
def spanning_tree(v, edges):
    parent = list(range(v))
    rank = [0] * v

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        root_x, root_y = find(x), find(y)
        if root_x == root_y:
            return False
        if rank[root_x] < rank[root_y]:
            root_x, root_y = root_y, root_x
        parent[root_y] = root_x
        if rank[root_x] == rank[root_y]:
            rank[root_x] += 1
        return True

    total_cost = 0
    for u, w, weight in sorted(edges, key=lambda e: e[2]):
        if union(u, w):
            total_cost += weight

    return total_cost

leetcode-1584-min-cost-to-connect-all-po.answer:
def min_cost_connect_points(points):
    n = len(points)
    edges = []
    for i in range(n):
        for j in range(i + 1, n):
            dist = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
            edges.append((i, j, dist))

    parent = list(range(n))

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        root_x, root_y = find(x), find(y)
        if root_x == root_y:
            return False
        parent[root_y] = root_x
        return True

    total_cost = 0
    edges_used = 0
    for u, v, w in sorted(edges, key=lambda e: e[2]):
        if union(u, v):
            total_cost += w
            edges_used += 1
            if edges_used == n - 1:
                break

    return total_cost

