leetcode-785-is-graph-bipartite.answer:
def is_bipartite(graph):
    from collections import deque

    n = len(graph)
    color = [-1] * n

    for start in range(n):
        if color[start] != -1:
            continue
        color[start] = 0
        queue = deque([start])
        while queue:
            node = queue.popleft()
            for neighbor in graph[node]:
                if color[neighbor] == -1:
                    color[neighbor] = 1 - color[node]
                    queue.append(neighbor)
                elif color[neighbor] == color[node]:
                    return False

    return True

geeksforgeeks-bipartite-graph.answer:
def is_bipartite_dfs(v, adj):
    color = [-1] * v

    def dfs(node, c):
        color[node] = c
        for neighbor in adj[node]:
            if color[neighbor] == -1:
                if not dfs(neighbor, 1 - c):
                    return False
            elif color[neighbor] == c:
                return False
        return True

    for start in range(v):
        if color[start] == -1:
            if not dfs(start, 0):
                return False
    return True

leetcode-1368-minimum-cost-to-make-at-le.answer:
def min_cost(grid):
    from collections import deque

    rows, cols = len(grid), len(grid[0])
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    dist = [[float('inf')] * cols for _ in range(rows)]
    dist[0][0] = 0
    dq = deque([(0, 0)])

    while dq:
        r, c = dq.popleft()
        for i, (dr, dc) in enumerate(directions):
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols:
                cost = 0 if grid[r][c] == i + 1 else 1
                new_dist = dist[r][c] + cost
                if new_dist < dist[nr][nc]:
                    dist[nr][nc] = new_dist
                    if cost == 0:
                        dq.appendleft((nr, nc))
                    else:
                        dq.append((nr, nc))

    return dist[rows - 1][cols - 1]

geeksforgeeks-0-1-bfs-shortest-path-in-a.answer:
def zero_one_bfs(v, adj, src):
    from collections import deque

    dist = [float('inf')] * v
    dist[src] = 0
    dq = deque([src])

    while dq:
        node = dq.popleft()
        for neighbor, weight in adj[node]:
            new_dist = dist[node] + weight
            if new_dist < dist[neighbor]:
                dist[neighbor] = new_dist
                if weight == 0:
                    dq.appendleft(neighbor)
                else:
                    dq.append(neighbor)

    return dist
